export function getTranslatedProject(project: { id: string; name: string; description: string; targetAudience: string; innovationReason: string }, language: string) {
  if (language === 'ro') return project;
  const pt = t[language]?.[project.id];
  if (!pt) return project;
  return {
    ...project,
    name: pt[0],
    description: pt[1],
    targetAudience: pt[2],
    innovationReason: pt[3],
  };
}
